  ('real-estate-moex-01622', 'real-estate', 'real-estate-moex-103-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '甲經紀營業員任職於乙經紀業，於執行業務過程中，甲有無以不動產說明書向與委託人交易之相對人丙 解說的義務？甲有無在不動產說明書上簽章的義務？', '["有解說義務，亦有簽章義務", "有解說義務，但無簽章義務", "無解說義務，但有簽章義務", "無解說義務，亦無簽章義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "465a45c6b93e", "answer_pdf_sha1": "c43a5bb3af14", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01623', 'real-estate', 'real-estate-moex-103-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '甲經紀營業員任職於乙經紀業，但乙經紀業同意甲為丙經紀業執行業務，是否符合法律規定？', '["符合法律規定，因為乙已同意", "不符合法律規定，因為甲有專任義務", "不符合法律規定，因為會有利益衝突", "不符合法律規定，因為此為雙方代理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "465a45c6b93e", "answer_pdf_sha1": "c43a5bb3af14", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01624', 'real-estate', 'real-estate-moex-103-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '有關經紀人員違反不動產經紀業管理條例相關規定者，下列之懲罰何者正確？', '["經紀人員收取差價者，應予六個月以上三年以下之停止執行業務處分", "經紀人員其已收取之差價或其他報酬，應於加計利息後返還支付人", "經紀人員受停止執行業務處分累計達三年以上者，廢止其經紀人員證書或證明", "中央主管機關對於經紀人員獎懲事項，應設置獎懲委員會處理之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "465a45c6b93e", "answer_pdf_sha1": "c43a5bb3af14", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01625', 'real-estate', 'real-estate-moex-103-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依不動產委託銷售定型化契約應記載及不得記載事項規定，服務報酬數額空白未記載者，則服務報酬如 何收取？', '["該不動產委託銷售定型化契約無效", "受託人不得向委託人收取服務報酬", "受託人可向委託人收取差價", "受託人最高可收取中央主管機關規定實際成交價百分之六的服務報酬"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "465a45c6b93e", "answer_pdf_sha1": "c43a5bb3af14", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01626', 'real-estate', 'real-estate-moex-103-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依不動產經紀業管理條例規定，受感訓處分之裁定確定者，可否充任不動產經紀人員？下列敍述何者正確？', '["永遠不得充任", "執行完畢後，即得充任", "執行完畢後滿一年者，始得充任", "尚未執行完畢者，不得充任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "465a45c6b93e", "answer_pdf_sha1": "c43a5bb3af14", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01627', 'real-estate', 'real-estate-moex-103-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依不動產經紀業管理條例規定，下列有關不動產說明書之相關敍述，何者錯誤？', '["不動產說明書應由經紀業指派經紀人簽章", "不動產說明書於提供解說前，應經委託人簽章", "以不動產說明書向委託人交易之相對人解說前，應由相對人在不動產說明書上簽章", "經買賣雙方簽章之不動產說明書視為買賣契約書之一部分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "465a45c6b93e", "answer_pdf_sha1": "c43a5bb3af14", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01628', 'real-estate', 'real-estate-moex-103-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依不動產經紀業管理條例規定，經紀業開始營業後自行停止營業至少連續多久時間以上，且未依法辦理 停業登記者，直轄市或縣（市）主管機關得廢止其許可？', '["三個月", "五個月", "六個月", "一年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "465a45c6b93e", "answer_pdf_sha1": "c43a5bb3af14", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01629', 'real-estate', 'real-estate-moex-103-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依不動產經紀業管理條例有關經營經紀業之規定，下列敍述何者錯誤？', '["應向主管機關申請許可後，依法辦理公司或商業登記", "經紀業分設營業處所，應向直轄市或縣（市）政府申請許可", "其經營國外不動產仲介業務者，應以公司型態組織依法辦理登記", "需加入登記所在地之同業公會後方得營業"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "465a45c6b93e", "answer_pdf_sha1": "c43a5bb3af14", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01630', 'real-estate', 'real-estate-moex-103-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '甲將其A屋出賣給乙，上開案件委由丙地政士與丁仲介業處理。請問應由誰向主管機關申報登錄實價？', '["甲", "乙", "丙", "丁"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "465a45c6b93e", "answer_pdf_sha1": "c43a5bb3af14", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01631', 'real-estate', 'real-estate-moex-103-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', 'A屋所有權人甲與不動產經紀人乙簽訂一般委託銷售定型化契約，關於該契約中的記載，以下敘述何者正確？', '["得約定本定型化契約及其附件之審閱期間僅有三日", "委託銷售之金額未記載者，本不動產委託銷售契約不當然無效", "未記載委託銷售期間者，甲仍不得隨時以書面終止", "如未記載乙服務報酬數額為實際成交價的百分比，乙仍得向甲收取最低額度的服務報酬"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "465a45c6b93e", "answer_pdf_sha1": "c43a5bb3af14", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
